module top_module(rst, clk, test, sync, freq, o);parameter WID = 32; 
input rst;
input clk;
input test;
input sync;
input [WID-1:0] freq;   
output [WID-1:0] o;

reg [WID-1:0] inv_acc;

always @(posedge clk)
if (rst)
    inv_acc <= 0;
else begin
    if (~test) begin
        if (sync)
            inv_acc <= 0;
        else
            inv_acc <= inv_acc + freq;
    end
    else
        inv_acc <= 0;
end

assign o = inv_acc;

endmodule
